package com.trademaster.ims.mobile.checkout.controller;import com.trademaster.ims.mobile.checkout.dto.CheckoutDtos.*;import com.trademaster.ims.mobile.checkout.service.MobileCheckoutService;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/mobile/v1")public class MobileCheckoutController{private final MobileCheckoutService s;public MobileCheckoutController(MobileCheckoutService s){this.s=s;}private long a(Authentication x){return s.account(x);}@GetMapping("/addresses")List<AddressResponse>list(Authentication x){return s.listAddresses(a(x));}@GetMapping("/addresses/{id}")AddressResponse get(Authentication x,@PathVariable long id){return s.getAddress(a(x),id);}@PostMapping("/addresses")@ResponseStatus(HttpStatus.CREATED)AddressResponse create(Authentication x,@Valid @RequestBody AddressRequest q){return s.createAddress(a(x),q);}@PutMapping("/addresses/{id}")AddressResponse update(Authentication x,@PathVariable long id,@Valid @RequestBody AddressRequest q){return s.updateAddress(a(x),id,q);}@DeleteMapping("/addresses/{id}")@ResponseStatus(HttpStatus.NO_CONTENT)void delete(Authentication x,@PathVariable long id){s.deleteAddress(a(x),id);}@PostMapping("/addresses/{id}/default")AddressResponse setDefault(Authentication x,@PathVariable long id){return s.setDefault(a(x),id);}@GetMapping("/delivery-methods")List<DeliveryMethodResponse>methods(Authentication x,@RequestParam(required=false)Long addressId){return s.deliveryMethods(addressId==null?null:a(x),addressId);}@PostMapping("/checkout/review")ReviewResponse review(Authentication x,@Valid @RequestBody ReviewRequest q){return s.review(a(x),q);}@PostMapping("/checkout/submit")OrderConfirmation submit(Authentication x,@Valid @RequestBody SubmitRequest q){return s.submit(a(x),q);}}
